import json
import requests

# RabbitMQ Management API endpoint and credentials
RABBITMQ_API_ENDPOINT = 'http://localhost:15672/api'
RABBITMQ_USERNAME = 'guest'
RABBITMQ_PASSWORD = 'guest'

def create_vhost(vhost_name):
    """Create a new virtual host"""
    url = f'{RABBITMQ_API_ENDPOINT}/vhosts/{vhost_name}'
    headers = {'Content-Type': 'application/json'}
    data = json.dumps({'name': vhost_name})
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USERNAME, RABBITMQ_PASSWORD), headers=headers, data=data)
        if response.status_code == 201:
            print(f'Virtual host {vhost_name} created successfully')
        else:
            print(f'Failed to create virtual host {vhost_name}: {response.text}')
    except requests.exceptions.RequestException as e:
        print(f'Error creating virtual host {vhost_name}: {e}')

def grant_permissions(vhost_name, username):
    """Grant permissions for queue operations"""
    url = f'{RABBITMQ_API_ENDPOINT}/permissions/{vhost_name}/{username}'
    headers = {'Content-Type': 'application/json'}
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USERNAME, RABBITMQ_PASSWORD), headers=headers)
        if response.status_code == 200:
            print(f'Permissions granted for {username} on virtual host {vhost_name}')
        else:
            print(f'Failed to grant permissions for {username} on virtual host {vhost_name}: {response.text}')
    except requests.exceptions.RequestException as e:
        print(f'Error granting permissions for {username} on virtual host {vhost_name}: {e}')

def create_user(username, password):
    """Create a new user"""
    url = f'{RABBITMQ_API_ENDPOINT}/users/{username}'
    headers = {'Content-Type': 'application/json'}
    data = json.dumps({'password': password})
    
    try:
        response = requests.put(url, auth=(RABBITMQ_USERNAME, RABBITMQ_PASSWORD), headers=headers, data=data)
        if response.status_code == 201:
            print(f'User {username} created successfully')
        else:
            print(f'Failed to create user {username}: {response.text}')
    except requests.exceptions.RequestException as e:
        print(f'Error creating user {username}: {e}')

# Create virtual hosts for different applications
vhosts = ['app1', 'app2', 'app3']
for vhost in vhosts:
    create_vhost(vhost)

# Create users and grant permissions
users = {
    'user1': {'password': 'password1', 'permissions': ['.*', '.*']},
    'user2': {'password': 'password2', 'permissions': ['.*', '.*']},
    'user3': {'password': 'password3', 'permissions': ['.*', '.*']}
}

for username, user in users.items():
    create_user(username, user['password'])
    grant_permissions('app1', username)